--- packages/ui/src/engine/pixel-characters.ts	2024-06-15 12:00:00.000000000 +0000
+++ packages/ui/src/engine/pixel-characters.ts	2024-06-15 12:00:00.000000000 +0000
@@ 3130,6 +3130,48 @@
+/**
+ * Draw a medieval parchment style tooltip near a character position.
+ * Shows character name, role, current status, and current task.
+ * @param ctx CanvasRenderingContext2D
+ * @param x Screen x coordinate near character
+ * @param y Screen y coordinate near character
+ * @param name Character name string
+ * @param role Character role string
+ * @param status Current status string
+ * @param task Current task string or null
+ */
+export function drawTooltip(
+  ctx: CanvasRenderingContext2D,
+  x: number,
+  y: number,
+  name: string,
+  role: string,
+  status: string,
+  task: string | null,
+) {
+  const padding = 8;
+  const lineHeight = 16;
+  const maxWidth = 220;
+
+  // Prepare lines of text
+  const lines = [
+    `Name: ${name}`,
+    `Role: ${role}`,
+    `Status: ${status}`,
+  ];
+  if (task) {
+    lines.push(`Task: ${task}`);
+  }
+
+  // Measure max text width
+  ctx.font = '14px serif';
+  let textWidth = 0;
+  for (const line of lines) {
+    const w = ctx.measureText(line).width;
+    if (w > textWidth) textWidth = w;
+  }
+  textWidth = Math.min(textWidth, maxWidth);
+
+  const boxWidth = textWidth + padding * 2;
+  const boxHeight = lines.length * lineHeight + padding * 2;
+
+  // Position tooltip above and to the right of (x,y), adjust if near edges
+  let bx = x + 12;
+  let by = y - boxHeight - 12;
+  if (bx + boxWidth > ctx.canvas.width) bx = x - boxWidth - 12;
+  if (by < 0) by = y + 12;
+
+  // Draw parchment background with scroll edges
+  ctx.save();
+  ctx.shadowColor = 'rgba(0,0,0,0.3)';
+  ctx.shadowBlur = 8;
+  ctx.shadowOffsetX = 2;
+  ctx.shadowOffsetY = 2;
+
+  // Background fill (parchment color)
+  const bgColor = '#f2e4b8';
+  const borderColor = '#a67c00';
+  ctx.fillStyle = bgColor;
+  ctx.strokeStyle = borderColor;
+  ctx.lineWidth = 3;
+  roundRect(ctx, bx, by, boxWidth, boxHeight, 10);
+  ctx.fill();
+  ctx.stroke();
+
+  // Draw decorative scroll curls top-left and bottom-right
+  ctx.strokeStyle = borderColor;
+  ctx.lineWidth = 2;
+  // Top-left curl
+  ctx.beginPath();
+  ctx.moveTo(bx + 6, by + 2);
+  ctx.bezierCurveTo(bx + 2, by + 2, bx + 2, by + 14, bx + 12, by + 14);
+  ctx.stroke();
+  // Bottom-right curl
+  ctx.beginPath();
+  ctx.moveTo(bx + boxWidth - 6, by + boxHeight - 2);
+  ctx.bezierCurveTo(bx + boxWidth - 2, by + boxHeight - 2, bx + boxWidth - 2, by + boxHeight - 14, bx + boxWidth - 12, by + boxHeight - 14);
+  ctx.stroke();
+
+  ctx.restore();
+
+  // Draw text lines
+  ctx.fillStyle = '#5a3a00';
+  ctx.font = '14px serif';
+  ctx.textBaseline = 'top';
+  for (let i = 0; i < lines.length; i++) {
+    ctx.fillText(lines[i], bx + padding, by + padding + i * lineHeight);
+  }
+}
+
